import{_ as i,o as e,c as t,ag as l}from"./chunks/framework.DtEl18Xn.js";const p="/getbiji-docs-v3/images/Ly3fb1mBJoZQq7xtp3Rcj1ranve.png",r="/getbiji-docs-v3/images/TxNcbRRbnozySuxEAskcagIcnAf.png",o="/getbiji-docs-v3/images/HZCebDxO7oNLHYxzojac7tAjnAc.png",u=JSON.parse('{"title":"设备指南","description":"","frontmatter":{"title":"设备指南","category":"GetSeed AI录音卡","lastUpdated":"2026-03-14T15:00:16.529Z"},"headers":[],"relativePath":"getseed-ai录音卡/设备指南.md","filePath":"getseed-ai录音卡/设备指南.md"}'),s={name:"getseed-ai录音卡/设备指南.md"};function n(d,a,c,h,g,m){return e(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="设备清单" tabindex="-1">设备清单 <a class="header-anchor" href="#设备清单" aria-label="Permalink to &quot;设备清单&quot;">​</a></h1><ul><li>1x GetSeed Card</li><li>1x 磁吸卡套</li><li>1x 磁吸环</li><li>1x 充电线</li><li>1x 录音卡说明书</li></ul><h1 id="基本功能键" tabindex="-1">基本功能键 <a class="header-anchor" href="#基本功能键" aria-label="Permalink to &quot;基本功能键&quot;">​</a></h1><p><img src="'+p+'" alt=""></p><h1 id="指示灯含义" tabindex="-1">指示灯含义 <a class="header-anchor" href="#指示灯含义" aria-label="Permalink to &quot;指示灯含义&quot;">​</a></h1><p><img src="'+r+'" alt=""></p><h1 id="为设备充电" tabindex="-1">为设备充电 <a class="header-anchor" href="#为设备充电" aria-label="Permalink to &quot;为设备充电&quot;">​</a></h1><p><img src="'+o+'" alt=""></p><p>USB 2.0（磁吸式Pogo pin接口），从 0 到 100% 需要约 1.5 小时即可充满电池。</p><p>续航能力强劲，最长连续录音约 35 小时，待机最长 60 天。</p><h1 id="设备基础参数" tabindex="-1">设备基础参数 <a class="header-anchor" href="#设备基础参数" aria-label="Permalink to &quot;设备基础参数&quot;">​</a></h1><p><strong>参数项</strong></p><p><strong>规格</strong></p><p>颜色</p><p>钛空灰</p><p>尺寸</p><p>54×85.6×3.1mm</p><p>重量</p><p>28.4g</p><p>厚度</p><p>3.1mm</p><p>存储</p><p>64GB</p><p>麦克风</p><p>3个</p><p>收音距离</p><p>8米</p><p>电池</p><p>400mAh</p><p>连续录音</p><p>35小时</p><p>待机时长</p><p>60天</p><p>蓝牙</p><p>v6.1</p><p>Wi-Fi</p><p>2.4G</p><p>录音模式</p><p>现场录音/通话录音（自动切换）</p><h1 id="开机-关机-休眠" tabindex="-1">开机/关机/休眠 <a class="header-anchor" href="#开机-关机-休眠" aria-label="Permalink to &quot;开机/关机/休眠&quot;">​</a></h1><ol><li><strong>开机</strong></li><li>长按 Mark 键 1 秒按钮开机，亮蓝灯一秒</li><li><strong>关机</strong></li><li>设备开机状态下，录音拨钮未开启状态</li><li>短按 Mark 键 7 次（相隔不超 过 0.5 秒），亮红灯 1 秒，设备关机</li><li><strong>休眠</strong></li><li>默认 3 小时不使用，设备自动休眠，不关机</li><li>休眠后再次连接设备时，短按 MARK 键 1 次可唤醒设备</li><li>休眠状态可进一步延长续航时间</li></ol><h1 id="强制重启设备" tabindex="-1">强制重启设备 <a class="header-anchor" href="#强制重启设备" aria-label="Permalink to &quot;强制重启设备&quot;">​</a></h1><ul><li>设备软件崩溃的时候，插上 USB 充电</li><li>短按 Mark 键三次（相隔不超过 0.5 秒）</li><li>再长按 3 秒，设备重启</li></ul><h1 id="恢复出厂设置" tabindex="-1">恢复出厂设置 <a class="header-anchor" href="#恢复出厂设置" aria-label="Permalink to &quot;恢复出厂设置&quot;">​</a></h1><ul><li>录音拨钮未开启状态</li><li>连按五下 MARK 键后再长按 5 秒，直到充电灯熄灭，振动两次，重置成功，<strong>全部数据清空</strong></li><li>恢复出厂设置支持在 APP 设置（点击设备→进入设备信息页→点底部「断开或解绑」→还原所有设置）</li></ul>',45)])])}const b=i(s,[["render",n]]);export{u as __pageData,b as default};
